  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
  type KangurMobileTone as Tone,
} from '../shared/KangurMobileUi';
import { translateKangurMobileActionLabel } from '../shared/translateKangurMobileActionLabel';
import {
  PRACTICE_COUNT_TONE,
  PRACTICE_KIND_TONE,
  formatPracticeQuestionCountLabel,
} from './practice-utils';

type PracticeCopy = (value: Record<string, string>) => string;

export interface PracticePreparationCardProps {
  copy: PracticeCopy;
  locale: KangurMobileLocale;
  practiceKindChipLabel: string;
  practiceModeHistoryHref: string;
  practiceSyncPreview: { body: string; label: string; tone: Tone };
  preparationLessonAction: React.ReactNode;
  questionsLength: number;
}

export function PracticePreparationCard({
  copy, locale, practiceKindChipLabel, practiceModeHistoryHref, practiceSyncPreview, preparationLessonAction, questionsLength,
}: PracticePreparationCardProps): React.JSX.Element {
  const renderInfo = (): React.JSX.Element => (
    <>
      <Text style={{ color: '#0f172a', fontSize: 22, fontWeight: '800' }}>{copy({ de: 'Trainingsplan', en: 'Session plan', pl: 'Plan sesji' })}</Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Zum Start siehst du hier den Umfang der Serie, den Speicherweg und die schnellsten Wege zurück zu Lektionen, Verlauf und Tagesplan.',
          en: 'At the start, this shows the run size, the save path, and the quickest routes back to lessons, history, and the daily plan.',
          pl: 'Na starcie widzisz tutaj rozmiar serii, sposób zapisu oraz najszybsze przejścia do lekcji, historii i planu dnia.',
        })}
      </Text>
    </>
  );

  return (
    <Card>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{copy({ de: 'Vor dem Start', en: 'Before you start', pl: 'Przed startem' })}</Text>
      {renderInfo()}
      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <Pill label={formatPracticeQuestionCountLabel(questionsLength, locale)} tone={PRACTICE_COUNT_TONE} />
        <Pill label={practiceKindChipLabel} tone={PRACTICE_KIND_TONE} />
        <Pill label={practiceSyncPreview.label} tone={practiceSyncPreview.tone} />
      </View>
      <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>{practiceSyncPreview.body}</Text>
      <View style={{ gap: 10 }}>
        {preparationLessonAction}
        <LinkButton borderRadius={16} centered href={practiceModeHistoryHref} label={translateKangurMobileActionLabel('View mode history', locale)} stretch tone='secondary' verticalPadding={12} />
        <LinkButton borderRadius={16} centered href={createKangurPlanHref()} label={translateKangurMobileActionLabel('Open daily plan', locale)} stretch tone='secondary' verticalPadding={12} />
      </View>
    </Card>
  );
}

import React from 'react';
import { KangurMobileAiTutorCard } from '../shared/KangurMobileUi';
import { PracticeCompletionCard } from './PracticeCompletionCard';
import { PracticePreparationCard } from './PracticePreparationCard';
import { PracticeQuestionDisplay } from './PracticeQuestionDisplay';
import { type PracticeData } from './practice-types';
import { type PracticePreparationCardProps } from './PracticePreparationCard';
import { type PracticeCompletionCardProps } from './PracticeCompletionCard';

interface PracticeScreenContentProps {
  data: PracticeData;
  actions: { handleNext: () => void };
  aiTutorContext: { contentId: string; surface: string };
  preparationCard: PracticePreparationCardProps | null;
  completionCard: PracticeCompletionCardProps | null;
}

export function PracticeScreenContent({
  data,
  actions,
  aiTutorContext,
  preparationCard,
  completionCard,
}: PracticeScreenContentProps): React.JSX.Element {
  const { currentQuestion, selectedChoice, isChoiceCorrect, currentIndex, questions, handleChoicePress } = data;

  return (
    <>
      <KangurMobileAiTutorCard context={aiTutorContext} />
      {preparationCard !== null ? <PracticePreparationCard {...preparationCard} /> : null}
      {completionCard !== null ? <PracticeCompletionCard {...completionCard} /> : null}
      {currentQuestion !== null && completionCard === null ? (
        <PracticeQuestionDisplay
          currentQuestion={currentQuestion}
          selectedChoice={selectedChoice}
          isChoiceCorrect={isChoiceCorrect}
          currentIndex={currentIndex}
          questionsLength={questions.length}
          locale={data.locale}
          handleChoicePress={handleChoicePress}
          onNext={actions.handleNext}
        />
      ) : null}
    </>
  );
}

import { type KangurLeaderboardItem, type KangurPracticeOperation } from '@kangur/core';
import { createDefaultKangurProgressState, type KangurProgressState, type KangurScore } from '@kangur/contracts/kangur';
import { useMemo, useSyncExternalStore } from 'react';

import { useKangurMobileI18n, type KangurMobileLocale } from '../i18n/kangurMobileI18n';
import { useKangurMobileLeaderboard } from '../leaderboard/useKangurMobileLeaderboard';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { useKangurMobileScoreHistory } from '../scores/useKangurMobileScoreHistory';
import {
  buildKangurPracticeSyncProofSnapshot,
  type KangurPracticeSyncProofSnapshot,
} from './practiceSyncProof';

type UseKangurPracticeSyncProofOptions = {
  enabled: boolean;
  expectedCorrectAnswers: number;
  expectedTotalQuestions: number;
  operation: KangurPracticeOperation;
  runStartedAt: number;
};

type UseKangurPracticeSyncProofResult = {
  error: string | null;
  isEnabled: boolean;
  isLoading: boolean;
  refresh: () => Promise<void>;
  snapshot: KangurPracticeSyncProofSnapshot;
};

const EMPTY_SNAPSHOT: KangurPracticeSyncProofSnapshot = {
  matchedScoreId: null,
  surfaces: [],
};

interface SnapshotParams {
  enabled: boolean;
  expectedCorrectAnswers: number;
  expectedTotalQuestions: number;
  leaderboardItems: KangurLeaderboardItem[];
  locale: KangurMobileLocale;
  operation: KangurPracticeOperation;
  progress: KangurProgressState;
  runStartedAt: number;
  scores: KangurScore[];
}

function calculateSnapshot(params: SnapshotParams): KangurPracticeSyncProofSnapshot {
  if (!params.enabled) {
    return EMPTY_SNAPSHOT;
  }

  return buildKangurPracticeSyncProofSnapshot({
    expectedCorrectAnswers: params.expectedCorrectAnswers,
    expectedTotalQuestions: params.expectedTotalQuestions,
    leaderboardItems: params.leaderboardItems,
    locale: params.locale,
    operation: params.operation,
    progress: params.progress,
    runStartedAt: params.runStartedAt,
    scores: params.scores,
  });
}

function getSyncError(
  leaderboardError: string | null,
  scoresQueryError: unknown,
  copy: (v: Record<string, string>) => string
): string | null {
  if (leaderboardError !== null) {
    return leaderboardError;
  }
  if (scoresQueryError instanceof Error) {
    return copy({
      de: 'Die Synchronisierungsvorschau konnte nicht aktualisiert werden.',
      en: 'Could not refresh the sync proof.',
      pl: 'Nie udało się odświeżyć podglądu synchronizacji.',
    });
  }
  return null;
}

export const useKangurPracticeSyncProof = ({
  enabled,
  expectedCorrectAnswers,
  expectedTotalQuestions,
  operation,
  runStartedAt,
}: UseKangurPracticeSyncProofOptions): UseKangurPracticeSyncProofResult => {
  const { progressStore } = useKangurMobileRuntime();
  const { copy, locale } = useKangurMobileI18n();
  const progress = useSyncExternalStore(
    progressStore.subscribeToProgress,
    progressStore.loadProgress,
    createDefaultKangurProgressState,
  );
  const scoresQuery = useKangurMobileScoreHistory({
    enabled,
    limit: 40,
    sort: '-created_date',
  });
  const leaderboard = useKangurMobileLeaderboard({
    enabled,
    limit: 100,
  });

  const snapshot = useMemo(() => calculateSnapshot({
    enabled,
    expectedCorrectAnswers,
    expectedTotalQuestions,
    leaderboardItems: leaderboard.items,
    locale,
    operation,
    progress,
    runStartedAt,
    scores: scoresQuery.scores,
  }), [
    enabled,
    expectedCorrectAnswers,
    expectedTotalQuestions,
    leaderboard.items,
    locale,
    operation,
    progress,
    runStartedAt,
    scoresQuery.scores,
  ]);

  const error = useMemo(
    () => getSyncError(leaderboard.error, scoresQuery.error, copy),
    [leaderboard.error, scoresQuery.error, copy]
  );

  return {
    error,
    isEnabled: enabled,
    isLoading: enabled && (scoresQuery.isLoading || leaderboard.isLoading),
    refresh: async () => {
      await Promise.all([scoresQuery.refresh(), leaderboard.refresh()]);
    },
    snapshot,
  };
};

import { Text, View } from 'react-native';
import {
  KangurMobileActionButton as ActionButton,
  KangurMobileCard as Card,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { formatKangurMobileScoreOperation } from '../../scores/mobileScoreSummary';
import { createKangurPlanHref } from '../../plan/planHref';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';
import { type UseKangurMobileProfileRecentResultsResult } from '../useKangurMobileProfileRecentResults';
import type { Href } from 'expo-router';

type ProfileResultsHubCardProps = {
  copy: KangurMobileCopy;
  locale: string;
  profileRecentResults: UseKangurMobileProfileRecentResultsResult;
  resultsRoute: Href;
};

function ResultsHubHeader({ copy, profileRecentResults }: { copy: KangurMobileCopy, profileRecentResults: UseKangurMobileProfileRecentResultsResult }): React.JSX.Element {
  const getMessage = (): string => {
    if (profileRecentResults.isLoading || profileRecentResults.isRestoringAuth) return copy({ de: 'Die gespeicherten Versuche für das Profil werden geladen.', en: 'Loading saved attempts for the profile.', pl: 'Pobieramy zapisane podejścia dla profilu.' });
    if (!profileRecentResults.isEnabled) return copy({ de: 'Melde dich an, um hier Ergebnisse und den vollständigen Verlauf zu sehen.', en: 'Sign in to see results and the full history here.', pl: 'Zaloguj się, aby zobaczyć tutaj wyniki i pełną historię.' });
    if (profileRecentResults.error !== null && profileRecentResults.error !== '') return profileRecentResults.error;
    return copy({ de: 'Stąd kannst du die Ergebnisse aktualisieren, die vollständige Historie öffnen und direkt den nächsten Lernschritt machen.', en: 'From here you can refresh results, open the full history, and jump straight into the next study step.', pl: 'Stąd możesz odświeżyć wyniki, otworzyć pełną historię i od razu przejść do kolejnego kroku nauki.' });
  };
  return (
    <View style={{ gap: 4 }}>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{copy({ de: 'Ergebnisse im Profil', en: 'Results in profile', pl: 'Wyniki w profilu' })}</Text>
      <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>{copy({ de: 'Ergebniszentrale', en: 'Results hub', pl: 'Centrum wyników' })}</Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>{getMessage()}</Text>
    </View>
  );
}

function ResultsHubMetrics({ copy, locale, profileRecentResults }: Pick<ProfileResultsHubCardProps, 'copy' | 'locale' | 'profileRecentResults'>): React.JSX.Element | null {
  const items = profileRecentResults.recentResultItems;
  const count = items.length;
  if (!profileRecentResults.isEnabled || profileRecentResults.isLoading || profileRecentResults.isRestoringAuth || (profileRecentResults.error !== null && profileRecentResults.error !== '') || count === 0) return null;

  const best = Math.max(...items.map((i) => (i.result.total_questions > 0 ? Math.round((i.result.correct_answers / i.result.total_questions) * 100) : 0)));
  const latest = items[0]?.result;
  return (
    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
      <Pill label={copy({ de: `Ergebnisse ${count}`, en: `Results ${count}`, pl: `Wyniki ${count}` })} tone={{ backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' }} />
      <Pill label={copy({ de: `Bestes Ergebnis ${best}%`, en: `Best accuracy ${best}%`, pl: `Najlepsza skuteczność ${best}%` })} tone={best >= 70 ? { backgroundColor: '#ecfdf5', borderColor: '#a7f3d0', textColor: '#047857' } : { backgroundColor: '#fef2f2', borderColor: '#fecaca', textColor: '#b91c1c' }} />
      {latest && <Pill label={copy({ de: `Letzter Modus ${formatKangurMobileScoreOperation(latest.operation, locale)}`, en: `Latest mode ${formatKangurMobileScoreOperation(latest.operation, locale)}`, pl: `Ostatni tryb ${formatKangurMobileScoreOperation(latest.operation, locale)}` })} tone={{ backgroundColor: '#f1f5f9', borderColor: '#cbd5e1', textColor: '#475569' }} />}
    </View>
  );
}

function ResultsHubActions({ copy, resultsRoute, refresh }: { copy: ProfileResultsHubCardProps['copy'], resultsRoute: Href, refresh: () => void }): React.JSX.Element {
  return (
    <View style={{ gap: 10 }}>
      <ActionButton label={copy({ de: 'Aktualisieren', en: 'Refresh', pl: 'Odśwież' })} onPress={refresh} stretch style={{ borderRadius: 16 }} tone='primary' verticalPadding={12} />
      <LinkButton href={resultsRoute} label={copy({ de: 'Vollständigen Verlauf öffnen', en: 'Open full history', pl: 'Otwórz pełną historię' })} stretch style={{ borderRadius: 16 }} verticalPadding={12} />
      <LinkButton href={createKangurPlanHref()} label={copy({ de: 'Tagesplan öffnen', en: 'Open daily plan', pl: 'Otwórz plan dnia' })} stretch style={{ borderRadius: 16 }} verticalPadding={12} />
    </View>
  );
}

export function ProfileResultsHubCard({ copy, locale, profileRecentResults, resultsRoute }: ProfileResultsHubCardProps): React.JSX.Element {
  return (
    <Card>
      <ResultsHubHeader copy={copy} profileRecentResults={profileRecentResults} />
      <ResultsHubMetrics copy={copy} locale={locale} profileRecentResults={profileRecentResults} />
      <ResultsHubActions copy={copy} resultsRoute={resultsRoute} refresh={() => void profileRecentResults.refresh()} />
    </Card>
  );
}

import type { KangurScoreListQuery } from '@kangur/contracts/kangur';
import type { KangurUser } from '@kangur/platform';

export type KangurMobileScoreScope = {
  identityKey: string;
  query: Pick<KangurScoreListQuery, 'created_by' | 'learner_id'>;
};

export const resolveKangurMobileScoreScope = (
  user: KangurUser | null | undefined,
): KangurMobileScoreScope | null => {
  const learnerId = user?.activeLearner?.id?.trim();
  if (learnerId) {
    return {
      identityKey: `learner:${learnerId}`,
      query: {
        learner_id: learnerId,
      },
    };
  }

  const email = user?.email?.trim();
  if (email) {
    return {
      identityKey: `email:${email.toLowerCase()}`,
      query: {
        created_by: email.toLowerCase(),
      },
    };
  }

  return null;
};

